// Define a structure to hold the count of numbers
typedef struct {
    int count;
} Count;

// Function to count the occurrences of each number in the input list
Count count_numbers(const int *numbers, int n) {
    Count count = {0};
    for (int i = 0; i < n; i++) {
        count.numbers[i] = numbers[i];
        count.count[i] = 1;
    }
    return count;
}

// Function to remove duplicates based on a threshold
int* remove_duplicates(const int *numbers, int n, int threshold) {
    if (n == 0) {
        return NULL;
    }

    // Create a count structure to keep track of the number of occurrences
    Count count = count_numbers(numbers, n);

    // Create a result array to hold the unique numbers
    int *result = (int *)malloc(n * sizeof(int));
    int result_index = 0;

    // Iterate through the input numbers and add to result if count <= threshold
    for (int i = 0; i < n; i++) {
        if (count.numbers[i] <= threshold) {
            result[result_index++] = count.numbers[i];
            count.count[i] = threshold + 1; // Mark as processed
        }
    }

    // Free the count structure
    free(count.numbers);

    return result;
}
